create table if not exists public.measurement (
  id uuid primary key default gen_random_uuid(),
  supabase_user_id uuid not null references public.profiles(id) on delete cascade,
  metric text not null,
  value double precision not null,
  recorded_at timestamptz not null,
  source text not null,
  created_at timestamptz not null default now(),
  updated_at timestamptz not null default now(),
  unique (supabase_user_id, metric, recorded_at)
);

create index if not exists idx_measurement_supabase_user_updated_at
  on public.measurement (supabase_user_id, updated_at desc);

alter table public.measurement enable row level security;

drop policy if exists measurement_select_own on public.measurement;
create policy measurement_select_own
  on public.measurement
  for select
  using (auth.uid() = supabase_user_id);

drop policy if exists measurement_insert_own on public.measurement;
create policy measurement_insert_own
  on public.measurement
  for insert
  with check (auth.uid() = supabase_user_id);

drop policy if exists measurement_update_own on public.measurement;
create policy measurement_update_own
  on public.measurement
  for update
  using (auth.uid() = supabase_user_id)
  with check (auth.uid() = supabase_user_id);

drop policy if exists measurement_delete_own on public.measurement;
create policy measurement_delete_own
  on public.measurement
  for delete
  using (auth.uid() = supabase_user_id);

