	public func withSuppressedSyncTriggers<T: Sendable>(
		_ work: @escaping @Sendable (Database) throws -> T
	) async throws -> T {
		try await database.write { db in
			try TriggerFlag.update { $0.isTriggersActive = false }.execute(db)
			defer { try? TriggerFlag.update { $0.isTriggersActive = true }.execute(db) }
			return try work(db)
		}
	}

	/// Suppresses sync triggers for the duration of **async** work (e.g. multiple `defaultDatabase.write` calls).
	///
	/// Prefer the ``withSuppressedSyncTriggers(_:)-1hqox`` overload when all SQL fits in one synchronous `(Database) throws` block.
	/// This variant toggles ``TriggerFlag`` across transactions; avoid overlapping inbound applies on the same database without external serialization.
	public func withSuppressedSyncTriggers<T: Sendable>(
		_ work: @escaping @Sendable () async throws -> T
	) async throws -> T {
		try await database.write { db in
			try TriggerFlag.update { $0.isTriggersActive = false }.execute(db)
		}
		let outcome: Result<T, Error>
		do {
			outcome = .success(try await work())
		} catch {
			outcome = .failure(error)
		}
		try await database.write { db in
			try TriggerFlag.update { $0.isTriggersActive = true }.execute(db)
		}
		switch outcome {
		case let .success(value):
			return value
		case let .failure(error):
			throw error
		}
	}
}

