import Foundation

/// Virtual avatar sync: there is **no** local SQLite table for `avatar_urls`.
///
/// - **Remote:** Supabase `public.avatar_urls` plus storage object paths (typically `"\(authUserId.uuidString).jpg"`).
/// - **Local queue:** `sync_entity.table_name` uses the same string as Postgres (`avatar_urls`) so inbound deltas and outbound routing stay aligned.
/// - **Local anchor:** `sync_entity.row_id` is the owning ``UserProfile`` primary key (`Int64`), not an `avatar_urls` row id.
public enum AvatarSyncMetadata: Sendable {
	public static let syncTableName = "avatar_urls"
}

