	static func linkRemoteId(remoteId: UUID, tableName: String, localRowId: Int64) -> some Statement<Void> {
		precondition(localRowId != 0, "linkRemoteId expects a real local row; placeholders use row_id 0")
		return Self.where { $0.table.eq(tableName) && $0.localRowId.eq(localRowId) }
			.update {
				$0.remoteId = #bind(remoteId)
				$0.state = SyncEntityState.synced
			}
	}

	/// Deletes `sync_entity` rows for a **virtual** table (no local domain table) that would violate the partial unique
	/// on `(table_name, row_id)` or duplicate the inbound remote key before inserting the reconciled row.
	static func deleteVirtualInboundConflicts(tableName: String, remoteId: UUID, localRowId: Int64) -> some Statement<Void> {
		precondition(localRowId != 0)
		return Self.where { $0.table.eq(tableName) && ($0.localRowId.eq(localRowId) || $0.remoteId.eq(remoteId)) }
			.delete()
	}

	/// Inserts the post-inbound anchor row for a virtual table (e.g. ``AvatarSyncMetadata/syncTableName``).
	static func insertSyncedVirtualEntity(tableName: String, remoteId: UUID, localRowId: Int64) -> some Statement<Void> {
		precondition(localRowId != 0)
		return Self.insert {
			Self.Draft(table: tableName, localRowId: localRowId, remoteId: remoteId, state: .synced)
		}
	}
}

