import Dependencies
import Foundation

/// **Writes only** for profile data the feature owns (name, identity, avatar file on disk, and outbound avatar queue via ``SyncClient``).
///
/// **Reads (module + app):** Use SQLiteData ``@FetchOne`` / ``@Fetch`` on state (e.g. ``EditProfile/State/profile``).
/// Do not add a `fetchProfile` API here—that duplicates the read path.
///
/// **App orchestration:** `prepareDependencies` installs ``ProfileClient/live``; integration/sync code reads rows with
/// `defaultDatabase` or existing fetches when building outbound handlers—registrations only need table names + push closures.
///
public struct ProfileClient: Sendable {
	public var updateName: @Sendable (String) async throws -> Void
	public var updateProfileIdentity: @Sendable (Date?, String?) async throws -> Void
	/// Encodes to JPEG, writes `"\(authUserId).jpg"` under the documents directory, then enqueues virtual avatar outbound sync (see ``AvatarSyncMetadata``).
	public var saveAvatar: @Sendable (Data) async throws -> Void
	/// Writes raw bytes to `documents/<fileName>` (e.g. server download). Does not touch SQLite; callers reconcile ``SyncEntity``.
	public var writeAvatarToDisk: @Sendable (Data, String) async throws -> Void
	/// Persists a full ``UserProfile`` row by primary key (typically after merging remote fields).
	public var upsertProfile: @Sendable (UserProfile) async throws -> Void

	public init(
		updateName: @escaping @Sendable (String) async throws -> Void,
		updateProfileIdentity: @escaping @Sendable (Date?, String?) async throws -> Void,
		saveAvatar: @escaping @Sendable (Data) async throws -> Void,
		writeAvatarToDisk: @escaping @Sendable (Data, String) async throws -> Void,
		upsertProfile: @escaping @Sendable (UserProfile) async throws -> Void
	) {
		self.updateName = updateName
		self.updateProfileIdentity = updateProfileIdentity
		self.saveAvatar = saveAvatar
		self.writeAvatarToDisk = writeAvatarToDisk
		self.upsertProfile = upsertProfile
	}
}

public extension ProfileClient {
	/// Crashes on any call — default in tests to catch missing dependency setup.
	static let unconfigured = ProfileClient(
		updateName: { _ in unimplemented() },
		updateProfileIdentity: { _, _ in unimplemented() },
		saveAvatar: { _ in unimplemented() },
		writeAvatarToDisk: { _, _ in unimplemented("ProfileClient.writeAvatarToDisk") },
		upsertProfile: { _ in unimplemented() }
	)
}

public enum ProfileClientKey: TestDependencyKey {
	public static let testValue = ProfileClient.unconfigured
	/// Same as ``ProfileClient/live``: writes go to ``DependencyValues/defaultDatabase`` and the app documents directory.
	/// Previews should install a database (e.g. `prepareDependencies { $0.defaultDatabase = … }`) and seed ``UserProfile`` if the scene exercises avatar flows.
	///
	/// For screens that also touch remote sync, override those dependencies in the same `prepareDependencies` block (e.g. your app’s `onlineStorage` with a stubbed ``TestDependencyKey/testValue``) so previews never reach production network services while local profile writes and UI still reflect what’s happening.
	public static var previewValue: ProfileClient { .live }
}

extension ProfileClientKey: DependencyKey {
	public static var liveValue: ProfileClient { .live }
}

public extension DependencyValues {
	var profileClient: ProfileClient {
		get { self[ProfileClientKey.self] }
		set { self[ProfileClientKey.self] = newValue }
	}
}

import Dependencies
import Foundation
import SQLiteData
import SyncFeature

public enum ProfileClientError: Error, Sendable {
	case userNotRegistered
	case invalidImageData
	case missingLocalUserProfile
}

public extension ProfileClient {
	/// Live implementation: ``defaultDatabase`` + documents directory; ``authUserId`` supplies the auth UUID for avatar paths (see ``DependencyValues/authUserId``).
	static var live: ProfileClient {
		@Dependency(\.defaultDatabase) var database
		@Dependency(\.authUserId) var authUserId
		@Dependency(\.syncClient) var syncClient
		return ProfileClient(
			updateName: { name in
				try await database.write { db in
					try UserProfile
						.update {
							$0.username = name
						}
						.execute(db)
				}
			},
			updateProfileIdentity: { dob, genderRaw in
				try await database.write { db in
					try UserProfile
						.update {
							$0.dateOfBirth = dob
							$0.gender = genderRaw
						}
						.execute(db)
				}
			},
			saveAvatar: { imageData in
				guard let userId = authUserId() else {
					throw ProfileClientError.userNotRegistered
				}
				let jpegData = try AvatarImageEncoding.jpegData(from: imageData)
				let fileName = "\(userId.uuidString).jpg"
				let profileId = try await database.read { db in
					guard let profile = try UserProfile.limit(1).fetchOne(db) else {
						throw ProfileClientError.missingLocalUserProfile
					}
					return profile.id
				}
				let documentsURL = FileManager.default.urls(for: .documentDirectory, in: .userDomainMask)[0]
				let fileURL = documentsURL.appendingPathComponent(fileName)
				if FileManager.default.fileExists(atPath: fileURL.path) {
					try FileManager.default.removeItem(at: fileURL)
				}
				try jpegData.write(to: fileURL)
				try await syncClient.enqueueAvatarOutbound(profileId)
			},
			writeAvatarToDisk: { imageData, fileName in
				let documentsURL = FileManager.default.urls(for: .documentDirectory, in: .userDomainMask)[0]
				let fileURL = documentsURL.appendingPathComponent(fileName)
				if FileManager.default.fileExists(atPath: fileURL.path) {
					try FileManager.default.removeItem(at: fileURL)
				}
				try imageData.write(to: fileURL)
			},
			upsertProfile: { row in
				try await database.write { db in
					try UserProfile.upsert {
						row
					}
					.execute(db)
				}
			}
		)
	}
}

