import Dependencies
import Foundation
import IssueReporting
import PacerCore
import ProfileFeature
import SQLiteData
import SyncFeature

extension InboundSyncRouter {
	// MARK: - `avatar_urls` inbound (Supabase; virtual local `sync_entity` — see ``AvatarSyncMetadata``)

	func applyAvatarURL(remoteId: String) async throws {
		let row: SupabaseAvatarURLRow = try await onlineStorage.fetchRow(
			for: RemoteSupabaseTable.avatarURLs,
			id: remoteId
		)
		if let sessionUserId = authUserId(), sessionUserId != row.userId {
			reportIssue(
				"InboundSyncRouter.applyAvatarURL: remote user_id \(row.userId) != authUserId() \(sessionUserId); single-user invariant may be broken"
			)
		}
		let data = try await onlineStorage.downloadAvatarFromStorage(row.fileName)
		try await profileClient.writeAvatarToDisk(data, row.fileName)

		let profile = try await database.read { db in
			guard let profile = try UserProfile.limit(1).fetchOne(db) else {
				reportIssue(
					"InboundSyncRouter.applyAvatarURL: missing local UserProfile; inbound merge should never run without a seeded profile"
