import Foundation
import PacerCore
import ProfileFeature
import SQLiteData
import SyncFeature
@testable import Stride

/// App test support: no ``ProfileClient/live``; inbound profile flows use ``InboundSyncRouter``’s live `switch` with stubbed ``OnlineStorageClient`` / ``ProfileClient`` in `withDependencies`.
///
/// Keep each helper narrowly scoped—only the behavior under test is implemented; everything else is a no-op or omitted.
enum ProfileIntegrationTestDoubles {
	/// Intentionally **not** production naming (live ``ProfileClient/live`` writes `UUID`.uuidString + `.jpg`).
	static let stubAvatarFileName = "stub-avatar-filename.test.jpg"

	/// Non-empty payloads for tests that call stub ``saveAvatar``; content is ignored.
	enum SaveAvatarPayload {
		static let a = Data([0x01])
		static let b = Data([0x02])
	}

	/// DB-only ``ProfileClient/saveAvatar`` for integration tests: enqueues virtual avatar sync (``AvatarSyncMetadata``) using the seeded profile id, no JPEG transcoding.
	/// Override only ``ProfileClient/saveAvatar`` in `withDependencies`: `$0.profileClient.saveAvatar = stubSaveAvatar(database: db)` (other endpoints stay `unimplemented()` via ``ProfileClientKey/testValue``).
	static func stubSaveAvatar(database: any DatabaseWriter) -> @Sendable (Data) async throws -> Void {
		{ imageData in
			guard !imageData.isEmpty else { throw ProfileClientError.invalidImageData }
			let hasRemoteUser = try await database.read { db -> Bool in
				guard let profile = try UserProfile.limit(1).fetchOne(db) else { return false }
				return try SyncEntity
					.where {
						$0.table.eq(ProfileSchema.UserProfile.tableName) && $0.localRowId.eq(profile.id)
					}
					.order { $0.id.desc() }
					.limit(1)
					.fetchOne(db)?
					.remoteId != nil
			}
			guard hasRemoteUser else { throw ProfileClientError.userNotRegistered }
			try await database.write { db in
				let profile = try #require(try UserProfile.limit(1).fetchOne(db))
				try SyncEntity.insert {
					SyncEntity.Draft(
						table: AvatarSyncMetadata.syncTableName,
						localRowId: profile.id,
						remoteId: nil,
						state: .outbound(.update)
					)
				}
				.execute(db)
			}
		}
	}
}

