import Foundation

// MARK: - Outbound (local pending row → remote)
//
// Triggers insert `sync_entity` with a **local** `table_name`. The app implements ``OutboundSyncApplying`` with a table `switch`
// (mirror ``InboundSyncApplying`` / ``InboundSyncRouter``).

/// Work item for outbound sync (local `sync_entity` → remote). Keeps this package free of app row types.
public struct OutboundSyncTask: Sendable, Equatable {
	public var table: String
	public var localRowId: Int64
	/// Raw `SyncOperation` string from the app schema (`insert` / `update` / `delete`).
	public var operation: String

	public init(table: String, localRowId: Int64, operation: String) {
		self.table = table
		self.localRowId = localRowId
		self.operation = operation
	}
}

// MARK: - Hexagonal ports (sync layer ↔ app)

/// Port the inbound pipeline calls after persisting remote deltas: **fetch** remote rows elsewhere, then **apply** by `tableName` + remote ids.
/// The app’s `InboundSyncRouter` implements this with a table `switch` and ``DependencyValues`` clients.
public protocol InboundSyncApplying: Sendable {
	func apply(tableName: String, id: String) async throws
}

/// Port for executing one outbound work item from `sync_entity`. Implement with a table + operation `switch`, mirroring inbound.
public protocol OutboundSyncApplying: Sendable {
	func handle(_ task: OutboundSyncTask) async throws
}

/// Legacy name for ``OutboundSyncApplying`` (queue and tests).
public typealias OutboundSyncDispatching = OutboundSyncApplying

public enum SyncRoutingError: Error, Sendable {
	case rowNotFound
}

import Dependencies
import Foundation
import JournalFeature
import PacerCore
import ProfileFeature
import SQLiteData
import SyncFeature

/// Outbound `sync_entity` work → remote. Mirrors ``InboundSyncRouter``: one entrypoint, `switch` on table, then on operation.
final class OutboundSyncRouter: OutboundSyncApplying, @unchecked Sendable {
	@Dependency(\.onlineStorage) var onlineStorage
	@Dependency(\.syncClient) var syncClient
	@Dependency(\.defaultDatabase) var database
	@Dependency(\.stravaAPI) var stravaAPI

	private let syncAvatarURLRow: (@Sendable (Int64) async throws -> Void)?
	private let uploadActivityStrava: (@Sendable (Int64) async throws -> Void)?

	init(
		syncAvatarURLRow: (@Sendable (Int64) async throws -> Void)? = nil,
		uploadActivityStrava: (@Sendable (Int64) async throws -> Void)? = nil
	) {
		self.syncAvatarURLRow = syncAvatarURLRow
		self.uploadActivityStrava = uploadActivityStrava
	}

	func handle(_ task: OutboundSyncTask) async throws {
		switch task.table {
		case AvatarSyncMetadata.syncTableName:
			try await handleAvatar(task)
		case Measurement.databaseTableName:
			try await handleMeasurement(task)
		case JournalSchema.Activities.tableName:
			try await handleActivity(task)
		case ActivityUpload.databaseTableName:
			try await handleActivityUpload(task)
		default:
			break
		}
	}

	private func handleAvatar(_ task: OutboundSyncTask) async throws {
		switch task.operation {
		case "insert", "update":
			if let syncAvatarURLRow {
				try await syncAvatarURLRow(task.localRowId)
			} else {
				try await onlineStorage.syncAvatarURL(task.localRowId)
			}
		case "delete":
			break
		default:
			break
		}
	}

	private func handleMeasurement(_ task: OutboundSyncTask) async throws {
		guard let measurement = try await database.read({ db in
			try Measurement.find(task.localRowId).fetchOne(db)
		}) else {
			throw SyncRoutingError.rowNotFound
		}
		try await onlineStorage.upsertMeasurement(measurement)
	}

	private func handleActivity(_ task: OutboundSyncTask) async throws {
		switch task.operation {
		case "insert", "update":
			let remoteId = try await onlineStorage.insertActivity(task.localRowId)
			try await syncClient.settleOutboundDelta(
				remoteId,
				JournalSchema.Activities.tableName,
				task.localRowId,
				.synced
			)
		case "delete":
			break
		default:
			break
		}
	}

	private func handleActivityUpload(_ task: OutboundSyncTask) async throws {
		guard let upload = try await database.read({ db in
			try ActivityUpload.find(task.localRowId).fetchOne(db)
		}) else { return }
		switch upload.platform {
		case .stravaAPI:
			if let uploadActivityStrava {
				try await uploadActivityStrava(upload.activityId)
			} else {
				try await stravaAPI.uploadActivity(upload.activityId)
			}
		default:
			break
		}
	}
}

