import Dependencies
import Foundation
import IssueReporting
import JournalFeature
import PacerCore
import ProfileFeature
import SQLiteData
import SyncFeature

extension InboundSyncRouter {

	// MARK: - `activities` inbound

	func applyActivity(remoteId: String) async throws {
		guard let remoteUUID = UUID(uuidString: remoteId) else {
			reportIssue("InboundSyncRouter: invalid UUID string '\(remoteId)' for activities")
			return
		}

		let syncRow = try await database.read { db in
			try SyncEntity.rowByRemoteId(
				tableName: JournalSchema.Activities.tableName,
				remoteId: remoteUUID
			)
			.fetchOne(db)
		}

		guard let syncRow else {
			reportIssue("InboundSyncRouter: no sync_entity found for activities remoteId \(remoteId)")
			return
		}

		switch syncRow.state.operation {
		case .delete:
			try await applyActivityDelete(syncRow: syncRow)
		case .insert, .update:
			try await applyActivityInsertOrUpdate(remoteId: remoteId, remoteUUID: remoteUUID, syncRow: syncRow)
		}
	}

	private func applyActivityInsertOrUpdate(remoteId: String, remoteUUID: UUID, syncRow: SyncEntity) async throws {
		let online: RemoteActivity = try await onlineStorage.fetchRow(
			for: JournalSchema.Activities.tableName,
			id: remoteId
		)

		if let sessionUserId = authUserId(), let remoteUser = online.userId, sessionUserId != remoteUser {
			reportIssue(
				"InboundSyncRouter.applyActivity: remote user_id \(remoteUser) != authUserId() \(sessionUserId); single-user invariant may be broken"
			)
		}

		let localActivityId = try await syncWriting.withSuppressedSyncTriggers { db -> Int64 in
			let knownLocalId = syncRow.localRowId
			if knownLocalId != 0 {
				guard let local = try Activity.find(knownLocalId).fetchOne(db) else {
					throw SyncRoutingError.rowNotFound
				}
				let merged = local.mergingInboundRemote(online)
				try Activity.find(knownLocalId)
					.update {
						$0.name = #bind(merged.name)
						$0.planId = #bind(merged.planId)
						$0.notes = #bind(merged.notes)
						$0.userId = #bind(merged.userId)
						$0.timestamp = #bind(merged.timestamp)
						$0.totalElapsedTime = #bind(merged.totalElapsedTime)
						$0.totalTimerTime = #bind(merged.totalTimerTime)
						$0.totalDistance = #bind(merged.totalDistance)
						$0.totalCalories = #bind(merged.totalCalories)
						$0.averageSpeed = #bind(merged.averageSpeed)
						$0.maxSpeed = #bind(merged.maxSpeed)
						$0.averageHeartRate = #bind(merged.averageHeartRate)
						$0.maxHeartRate = #bind(merged.maxHeartRate)
						$0.averageCadence = #bind(merged.averageCadence)
						$0.maxCadence = #bind(merged.maxCadence)
						$0.totalAscent = #bind(merged.totalAscent)
						$0.totalDescent = #bind(merged.totalDescent)
						$0.sport = #bind(merged.sport)
						$0.avgTemperature = #bind(merged.avgTemperature)
						$0.maxTemperature = #bind(merged.maxTemperature)
						$0.trainingEffect = #bind(merged.trainingEffect)
						$0.updatedAt = #bind(merged.updatedAt)
					}
					.execute(db)
				return knownLocalId
			}

			guard !inboundActivityExistsNear(timestamp: online.timestamp, db) else {
				reportIssue("InboundSyncRouter.applyActivity: duplicate local activity near timestamp \(online.timestamp)")
				throw SyncRoutingError.rowNotFound
			}
			let startOfDay = Calendar.current.startOfDay(for: online.timestamp)
			guard let journalEntry = try fetchOrCreateJournalEntry(startOfDay, db) else {
				throw SyncRoutingError.rowNotFound
			}
			let draft = Activity.Draft(remote: online, journalId: journalEntry.id)
			guard let activityId = try Activity.insert { draft }.returning(\.id).fetchOne(db) else {
				throw SyncRoutingError.rowNotFound
			}
			return activityId
		}

		try await database.write { db in
			try SyncEntity
				.where {
					$0.table.eq(JournalSchema.Activities.tableName) && $0.remoteId.eq(remoteUUID)
				}
				.update {
					$0.localRowId = #bind(localActivityId)
					$0.state = #bind(SyncEntityState.synced)
				}
				.execute(db)
		}

		try await syncClient.settleInboundDelta(
			remoteUUID,
			JournalSchema.Activities.tableName,
			localActivityId,
			.synced
		)
	}

	// MARK: - Delete

	private func applyActivityDelete(syncRow: SyncEntity) async throws {
		let localRowId = syncRow.localRowId

		guard localRowId != 0 else { return }

		try await syncWriting.withSuppressedSyncTriggers { db in
			try Activity.find(localRowId).delete().execute(db)
		}
	}

	private func fetchOrCreateJournalEntry(_ date: Date, _ db: Database) throws -> JournalEntry? {
		let startOfDay = Calendar.current.startOfDay(for: date)
		try JournalEntry.insert {
			($0.date, $0.notes)
		} values: {
			(startOfDay, nil)
		} onConflict: {
			($0.date)
		} doUpdate: { _, _ in }
		.execute(db)
		return try JournalEntry
			.where { $0.date.eq(startOfDay) }
			.limit(1)
			.fetchOne(db)
	}

	private func inboundActivityExistsNear(timestamp: Date, _ db: Database) -> Bool {
		guard let trimmed = Calendar.current.date(
			from: Calendar.current.dateComponents(
				[.year, .month, .day, .hour, .minute, .second],
				from: timestamp
			)
		) else { return false }

		do {
			let windowEnd = trimmed.addingTimeInterval(1)
			return try Activity
				.where { $0.timestamp.between(trimmed, and: windowEnd) }
				.limit(1)
				.fetchOne(db) != nil
		} catch {
			return false
		}
	}
}

private extension Activity {
	func mergingInboundRemote(_ remote: RemoteActivity) -> Activity {
		var copy = self
		copy.name = remote.name
		copy.planId = remote.planId
		copy.notes = remote.notes
		copy.userId = remote.userId
		copy.timestamp = remote.timestamp
		copy.totalElapsedTime = remote.totalElapsedTime
		copy.totalTimerTime = remote.totalTimerTime
		copy.totalDistance = remote.totalDistance
		copy.totalCalories = remote.totalCalories
		copy.averageSpeed = remote.averageSpeed
		copy.maxSpeed = remote.maxSpeed
		copy.averageHeartRate = remote.averageHeartRate
		copy.maxHeartRate = remote.maxHeartRate
		copy.averageCadence = remote.averageCadence
		copy.maxCadence = remote.maxCadence
		copy.totalAscent = remote.totalAscent
		copy.totalDescent = remote.totalDescent
		copy.sport = remote.sport
		copy.avgTemperature = remote.avgTemperature
		copy.maxTemperature = remote.maxTemperature
		copy.trainingEffect = remote.trainingEffect
		copy.updatedAt = .now
		return copy
	}
}

