private func diffLocal(with changes: [Delta]) -> [Delta] {
	// only fetches locals with a remote id
	// since if they dont have one yet then they should be a remote insert
	// scenario: reinstall / second device
	let localPending = syncClient.localPendingChanges()

	// local keyed by remoteId (UUID?), remote keyed by id parsed as UUID
	let localById = Dictionary(
		uniqueKeysWithValues: localPending.compactMap { event -> (UUID, SyncEntity)? in
			guard let id = event.remoteId else { return nil }
			return (id, event)
		}
	)

	let remoteById = Dictionary(
		uniqueKeysWithValues: changes.compactMap { delta -> (UUID, Delta)? in
			guard let uuid = UUID(uuidString: delta.id) else { return nil }
			return (uuid, delta)
		}
	)
	let allIds = Set(localById.keys).union(remoteById.keys)

	var keepLocal: [SyncEntity] = []
	var keepRemote: [Delta] = []

	// if there is a match on id/table then
	// if local < online, delete local
	// else remove online
	for id in allIds {
		switch (localById[id], remoteById[id]) {
		case let (.some(l), .some(r)):
			if l.updatedAt > r.updatedAt { keepLocal.append(l) }
			else if r.updatedAt > l.updatedAt { keepRemote.append(r) }
			// equal → do nothing
		case let (.some(l), .none):
			keepLocal.append(l)
		case let (.none, .some(r)):
			keepRemote.append(r)
		default:
			break
		}
	}

	// Only remove pending rows that participated in this reconciliation and lost to remote.
	// Unrelated outbound work (e.g. avatar rows with no `remote_id` yet) must stay queued.
	let reconciledIds = Set(localPending.map(\.id))
	let winningIds = Set(keepLocal.map(\.id))
	let losingIds = reconciledIds.subtracting(winningIds)
	try? database.write { db in
		if !losingIds.isEmpty {
			try SyncEntity
				.where { $0.id.in(Array(losingIds)) }
				.delete()
				.execute(db)
		}
	}

	return keepRemote
}

