import Foundation

public enum PendingDeltaReconciliation {
	/// Pairs outbound locals (with `remote_id`) against remote deltas. Same `(table, remote UUID)` uses newest `updatedAt`; remote-newer clashes yield `loserSyncEntityIds` and include that delta in `inbound`.
	public static func reconcile(
		localPendingWithRemoteId: [SyncEntity],
		remoteDeltas: [RemoteTableDelta]
	) -> (inbound: [RemoteTableDelta], loserSyncEntityIds: [Int64]) {
		func key(_ table: String, _ id: UUID) -> String { "\(table)|\(id.uuidString)" }
		var deltaBy = [String: RemoteTableDelta]()
		for d in remoteDeltas {
			guard let u = UUID(uuidString: d.id) else { continue }
			deltaBy.merge([key(d.tableName, u): d]) { $0.updatedAt >= $1.updatedAt ? $0 : $1 }
		}
		var localBy = [String: SyncEntity]()
		for e in localPendingWithRemoteId {
			guard let r = e.remoteId else { continue }
			localBy.merge([key(e.table, r): e]) { $0.updatedAt >= $1.updatedAt ? $0 : $1 }
		}
		var losers = [Int64]()
		var inbound = [RemoteTableDelta]()
		for k in localBy.keys where deltaBy[k] != nil {
			if let l = localBy[k], let d = deltaBy[k], d.updatedAt > l.updatedAt {
				losers.append(l.id)
				inbound.append(d)
			}
		}
		for k in deltaBy.keys where localBy[k] == nil {
			if let d = deltaBy[k] { inbound.append(d) }
		}
		return (inbound, losers)
	}
}

