import ComposableArchitecture
import Dependencies
import Foundation
import JournalFeature
import SQLiteData
import SyncFeature
import Testing

@testable import Stride

private struct SlowNoOpInboundSyncApplying: InboundSyncApplying {
	var delay: Duration

	func apply(tableName: String, id: String) async throws {
		try await Task.sleep(for: delay)
	}
}

private final class FetchChangesSpy: @unchecked Sendable {
	var count = 0
}

extension BaseTestSuite {
	@MainActor
	struct PendingSyncQueueMergeTests {
		@Dependency(\.defaultDatabase) var database

		/// ``PendingSyncQueue`` `mergeInboundDeltas`: live DB + live ``SyncClient`` for `localPendingChanges` / `enqueueInboundDelta`, stubbed ``OnlineStorageClient/fetchChanges``, pacer row authorised, ``NetworkMonitorKey/testValue`` (always online). Slow no-op inbound router so polling can observe the loser row flipped to ``SyncEntityState/inbound(.update)`` before apply finishes.
		@Test
		func pendingSyncQueue_mergeInboundDeltas_remoteNewer_flipsOutboundRowToInboundUpdate() async throws {
			let remoteId = UUID(uuidString: "00000000-0000-0000-0000-00000000A001")!
			let tLocal = Date(timeIntervalSince1970: 50)
			let tRemote = Date(timeIntervalSince1970: 150)
			let table = JournalSchema.Activities.tableName
			let fetchSpy = FetchChangesSpy()
			let liveSync = SyncClient.live

			try await withDependencies {
				$0.inboundSyncRouter = SlowNoOpInboundSyncApplying(delay: .milliseconds(150))
				var online = OnlineStorageClient.testValue
				online.fetchChanges = .init { _ in
					fetchSpy.count += 1
					return OnlineDiff(deltas: [
						Delta(
							id: remoteId.uuidString,
							tableName: table,
							updatedAt: tRemote,
							isDeleted: false
						),
					])
				}
				$0.onlineStorage = online
				$0.syncClient = SyncClient(
					settleInboundDelta: liveSync.settleInboundDelta,
					settleOutboundDelta: liveSync.settleOutboundDelta,
					linkedRemoteId: liveSync.linkedRemoteId,
					enqueueInboundDelta: liveSync.enqueueInboundDelta,
					enqueueOutboundDelta: liveSync.enqueueOutboundDelta,
					localPendingChanges: liveSync.localPendingChanges
				)
			} operation: {
				try await database.write { db in
					try SyncEntity
						.where { !$0.state.eq(SyncEntityState.synced) }
						.update { $0.state = #bind(SyncEntityState.synced) }
						.execute(db)
					try ActivitySourceIntegration.update {
						$0.isAuthorised = true
					}
					.where { $0.id.eq(ActivitySource.pacer) }
					.execute(db)
					try SyncEntity.insert {
						SyncEntity.Draft(
							table: table,
							localRowId: 1,
							remoteId: remoteId,
							state: .outbound(.update)
						)
					}
					.execute(db)
					try SyncEntity
						.where { $0.table.eq(table) && $0.remoteId.eq(remoteId) }
						.update { $0.updatedAt = #bind(tLocal) }
						.execute(db)
				}

				let entityId = try await database.read { db in
					try SyncEntity.rowByRemoteId(tableName: table, remoteId: remoteId)
						.fetchOne(db)?
						.id
				}
				let eid = try #require(entityId)

				_ = PendingSyncQueue()

				var sawLoserInboundUpdate = false
				for _ in 0 ..< 80 {
					try await Task.sleep(for: .milliseconds(5))
					let state = try await database.read { db in
						try SyncEntity.find(eid).fetchOne(db)?.state
					}
					if state == .inbound(.update) {
						sawLoserInboundUpdate = true
						break
					}
				}

				#expect(fetchSpy.count >= 1)
				#expect(sawLoserInboundUpdate)
			}
		}
	}
}

